 Simple A/B Testing with Nginx split_clients ngx_http_split_clients_module Configure For example, suppose we want 20% of users to be redirected to https://example.com/, 30% to https://example.org/, and the rest to https://example.edu/.
split_clients &#34;${remote_addr}AAA&#34; $variant { 20% https://example.com/; 30% https://example.org/; * https://example.edu/; } server { listen 80; listen [::]:80; server_name _; return 302 ${variant}; } In the example above, the visitor&rsquo;s IP address plus the string AAA is hashed with MurmurHash2 into a number. If the number falls in the first 20%, $variant is https://example.com/. If it falls in the middle 30%, $variant is https://example.org/. Otherwise it is https://example.edu/.
Specify different directories root /var/www/${variant}; Specify different index pages index index-${variant}.html;

 How Go Reads a 16GB File in 25 Seconds Reading 16GB File in Seconds, Golang After opening the file, we have two options:
Read the file line by line, which reduces memory pressure but takes more time. Read the entire file into memory and process it, which uses more memory but significantly reduces time. Because the file is too large (16 GB), we cannot load the entire file into memory. But the first option is also not feasible for us because we want to process the file within seconds.
But guess what, there is a third option. Look&hellip; In Go, instead of loading the entire file into memory, we can use bufio.NewReader() to read the file in chunks.
func main() { s := time.Now() args := os.Args[1:] if len(args) != 6 { // for format LogExtractor.exe -f &#34;From Time&#34; -t &#34;To Time&#34; -i &#34;Log file directory location&#34; fmt.Println(&#34;Please give proper command line arguments&#34;) return } startTimeArg := args[1] finishTimeArg := args[3] fileName := args[5] file, err := os.Open(fileName) if err != nil { fmt.Println(&#34;cannot able to read the file&#34;, err) return } defer file.Close() // close after checking err queryStartTime, err := time.Parse(&#34;2006-01-02T15:04:05.0000Z&#34;, startTimeArg) if err != nil { fmt.Println(&#34;Could not able to parse the start time&#34;, startTimeArg) return } queryFinishTime, err := time.Parse(&#34;2006-01-02T15:04:05.0000Z&#34;, finishTimeArg) if err != nil { fmt.Println(&#34;Could not able to parse the finish time&#34;, finishTimeArg) return } filestat, err := file.Stat() if err != nil { fmt.Println(&#34;Could not able to get the file stat&#34;) return } fileSize := filestat.Size() offset := fileSize - 1 lastLineSize := 0 for { b := make([]byte, 1) n, err := file.ReadAt(b, offset) if err != nil { fmt.Println(&#34;Error reading file &#34;, err) break } char := string(b[0]) if char == &#34;
&#34; { break } offset-- lastLineSize += n } lastLine := make([]byte, lastLineSize) _, err = file.ReadAt(lastLine, offset+1) if err != nil { fmt.Println(&#34;Could not able to read last line with offset&#34;, offset, &#34;and lastline size&#34;, lastLineSize) return } logSlice := strings.SplitN(string(lastLine), &#34;,&#34;, 2) logCreationTimeString := logSlice[0] lastLogCreationTime, err := time.Parse(&#34;2006-01-02T15:04:05.0000Z&#34;, logCreationTimeString) if err != nil { fmt.Println(&#34;can not able to parse time : &#34;, err) } if lastLogCreationTime.After(queryStartTime) &amp;&amp; lastLogCreationTime.Before(queryFinishTime) { Process(file, queryStartTime, queryFinishTime) } fmt.Println(&#34;
Time taken - &#34;, time.Since(s)) } func Process(f *os.File, start time.Time, end time.Time) error { linesPool := sync.Pool{New: func() interface{} { lines := make([]byte, 250*1024) return lines }} stringPool := sync.Pool{New: func() interface{} { lines := &#34;&#34; return lines }} r := bufio.NewReader(f) var wg sync.WaitGroup for { buf := linesPool.Get().([]byte) n, err := r.Read(buf) buf = buf[:n] if n == 0 { if err != nil { fmt.Println(err) break } if err == io.EOF { break } return err } nextUntillNewline, err := r.ReadBytes(&#39;
&#39;) if err != io.EOF { buf = append(buf, nextUntillNewline...) } wg.Add(1) go func() { ProcessChunk(buf, &amp;linesPool, &amp;stringPool, start, end) wg.Done() }() } wg.Wait() return nil } func ProcessChunk(chunk []byte, linesPool *sync.Pool, stringPool *sync.Pool, start time.Time, end time.Time) { var wg2 sync.WaitGroup logs := stringPool.Get().(string) logs = string(chunk) linesPool.Put(chunk) logsSlice := strings.Split(logs, &#34;
&#34;) stringPool.Put(logs) chunkSize := 300 n := len(logsSlice) noOfThread := n / chunkSize if n%chunkSize != 0 { noOfThread++ } for i := 0; i &lt; (noOfThread); i++ { wg2.Add(1) go func(s int, e int) { defer wg2.Done() // to avaoid deadlocks for i := s; i &lt; e; i++ { text := logsSlice[i] if len(text) == 0 { continue } logSlice := strings.SplitN(text, &#34;,&#34;, 2) logCreationTimeString := logSlice[0] logCreationTime, err := time.Parse(&#34;2006-01-02T15:04:05.0000Z&#34;, logCreationTimeString) if err != nil { fmt.Printf(&#34;
 Could not able to parse the time :%s for log : %v&#34;, logCreationTimeString, text) return } if logCreationTime.After(start) &amp;&amp; logCreationTime.Before(end) { // fmt.Println(text) } } }(i*chunkSize, int(math.Min(float64((i+1)*chunkSize), float64(len(logsSlice))))) } wg2.Wait() logsSlice = nil }

